// worker-gateway.js - Public-facing worker
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;

    try {
      if (path.startsWith('/api/users')) {
        return await env.USER_SERVICE.fetch(request);
      } else if (path.startsWith('/api/products')) {
        return await env.PRODUCT_SERVICE.fetch(request);
      } else if (path.startsWith('/api/orders')) {
        return await env.ORDER_SERVICE.fetch(request);
      } else if (path.startsWith('/api/analytics')) {
        return await env.ANALYTICS_SERVICE.fetch(request);
      } else if (path === '/health') {
        const services = {
          user: await checkServiceHealth(env.USER_SERVICE),
          product: await checkServiceHealth(env.PRODUCT_SERVICE),
          order: await checkServiceHealth(env.ORDER_SERVICE),
          analytics: await checkServiceHealth(env.ANALYTICS_SERVICE)
        };
        
        return new Response(JSON.stringify({
          status: 'ok',
          services
        }), {
          headers: { 'Content-Type': 'application/json' }
        });
      } else {
        return new Response(JSON.stringify({
          error: 'Not Found',
          message: 'The requested endpoint does not exist'
        }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' }
        });
      }
    } catch (error) {
      return new Response(JSON.stringify({
        error: 'Internal Server Error',
        message: error.message
      }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' }
      });
    }
  }
};

async function checkServiceHealth(service) {
  try {
    const response = await service.fetch(new Request('http://internal/health'));
    return response.ok ? 'healthy' : 'unhealthy';
  } catch (error) {
    return 'error';
  }
}

// worker-user-service.js - User service worker
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;

    if (path === '/health') {
      return new Response(JSON.stringify({ status: 'ok', service: 'user' }), {
        headers: { 'Content-Type': 'application/json' }
      });
    }

    try {
      if (path === '/api/users' && method === 'GET') {
        const users = await env.USER_KV.get('users', { type: 'json' }) || [];
        return new Response(JSON.stringify({ users }), {
          headers: { 'Content-Type': 'application/json' }
        });
      } else if (path === '/api/users' && method === 'POST') {
        const userData = await request.json();
        const userId = crypto.randomUUID();
        const user = { id: userId, ...userData, createdAt: new Date().toISOString() };
        
        const users = await env.USER_KV.get('users', { type: 'json' }) || [];
        users.push(user);
        await env.USER_KV.put('users', JSON.stringify(users));
        
        if (env.ANALYTICS_SERVICE) {
          ctx.waitUntil(
            env.ANALYTICS_SERVICE.fetch(new Request('http://internal/api/analytics/event', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({
                event: 'user_created',
                userId: userId,
                timestamp: new Date().toISOString()
              })
            }))
          );
        }
        
        return new Response(JSON.stringify({ user }), {
          status: 201,
          headers: { 'Content-Type': 'application/json' }
        });
      } else if (path.match(/^\/api\/users\/[^/]+$/) && method === 'GET') {
        const userId = path.split('/').pop();
        const users = await env.USER_KV.get('users', { type: 'json' }) || [];
        const user = users.find(u => u.id === userId);
        
        if (!user) {
          return new Response(JSON.stringify({ error: 'User not found' }), {
            status: 404,
            headers: { 'Content-Type': 'application/json' }
          });
        }
        
        return new Response(JSON.stringify({ user }), {
          headers: { 'Content-Type': 'application/json' }
        });
      } else if (path.match(/^\/api\/users\/[^/]+$/) && method === 'PUT') {
        const userId = path.split('/').pop();
        const updateData = await request.json();
        const users = await env.USER_KV.get('users', { type: 'json' }) || [];
        const userIndex = users.findIndex(u => u.id === userId);
        
        if (userIndex === -1) {
          return new Response(JSON.stringify({ error: 'User not found' }), {
            status: 404,
            headers: { 'Content-Type': 'application/json' }
          });
        }
        
        users[userIndex] = { ...users[userIndex], ...updateData, updatedAt: new Date().toISOString() };
        await env.USER_KV.put('users', JSON.stringify(users));
        
        return new Response(JSON.stringify({ user: users[userIndex] }), {
          headers: { 'Content-Type': 'application/json' }
        });
      } else if (path.match(/^\/api\/users\/[^/]+$/) && method === 'DELETE') {
        const userId = path.split('/').pop();
        const users = await env.USER_KV.get('users', { type: 'json' }) || [];
        const filteredUsers = users.filter(u => u.id !== userId);
        
        if (users.length === filteredUsers.length) {
          return new Response(JSON.stringify({ error: 'User not found' }), {
            status: 404,
            headers: { 'Content-Type': 'application/json' }
          });
        }
        
        await env.USER_KV.put('users', JSON.stringify(filteredUsers));
        
        return new Response(JSON.stringify({ message: 'User deleted' }), {
          headers: { 'Content-Type': 'application/json' }
        });
      }
      
      return new Response(JSON.stringify({ error: 'Method not allowed' }), {
        status: 405,
        headers: { 'Content-Type': 'application/json' }
      });
    } catch (error) {
      return new Response(JSON.stringify({ error: error.message }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' }
      });
    }
  }
};

